import { useEffect, useState } from "react";
import { API } from "../api/base";
import "./CompanyDashboard.scss";

export default function CompanyDashboard() {
  const companyName =
    localStorage.getItem("username") || "Company";

  const token = localStorage.getItem("token");

  const [analytics, setAnalytics] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  /* =========================
     FETCH COMPANY ANALYTICS
  ========================= */
  useEffect(() => {
    const fetchAnalytics = async () => {
      try {
        console.log("Using API:", API);

        const res = await fetch(
          `${API}/api/company/analytics`,
          {
            headers: {
              Authorization: `Bearer ${token}`,
              "Content-Type": "application/json",
            },
          }
        );

        if (!res.ok) {
          throw new Error("Failed to fetch analytics");
        }

        const data = await res.json();
        setAnalytics(data);
      } catch (err) {
        console.error("Analytics error:", err);
        setError("Unable to load analytics");
      } finally {
        setLoading(false);
      }
    };

    if (token) {
      fetchAnalytics();
    } else {
      setLoading(false);
      setError("No authentication token found");
    }
  }, [token]);

  return (
    <div className="company-dashboard">
      <header className="company-header">
        <h1>{companyName}</h1>

        <button
          className="logout-btn"
          onClick={() => {
            localStorage.clear();
            window.location.href = "/";
          }}
        >
          Logout
        </button>
      </header>

      {/* =========================
         ANALYTICS SECTION
      ========================= */}

      {loading && <p>Loading analytics...</p>}

      {error && <p style={{ color: "red" }}>{error}</p>}

      {analytics && (
        <div className="stats-row">

          <div className="stat-box">
            <h3>Total Bugs</h3>
            <p>{analytics.totalBugs || 0}</p>
          </div>

          <div className="stat-box">
            <h3>Pending</h3>
            <p>{analytics.pendingBugs || 0}</p>
          </div>

          <div className="stat-box">
            <h3>Approved</h3>
            <p>{analytics.approvedBugs || 0}</p>
          </div>

          <div className="stat-box">
            <h3>Total Paid</h3>
            <p>₹{analytics.totalPaid || 0}</p>
          </div>

          <div className="stat-box wallet">
            <h3>Wallet Balance</h3>
            <p>₹{analytics.walletBalance || 0}</p>
          </div>

        </div>
      )}

      {/* =========================
         DASHBOARD CARDS
      ========================= */}

      <div className="dashboard-cards">
        <div
          className="dashboard-card"
          onClick={() => (window.location.href = "/company/pending")}
        >
          <h2>New Bugs</h2>
          <p>Review & take action</p>
        </div>

        <div
          className="dashboard-card"
          onClick={() => (window.location.href = "/company/history")}
        >
          <h2>Bug History</h2>
          <p>Approved, rejected & duplicate</p>
        </div>
      </div>

    </div>
  );
}
